class Box:
    def __init__(self, w, h):
        self.width = w
        self.height = h

    def area(self):
        return self.width * self.height

    def describe(self):
        return f"{self.width}x{self.height} = {self.area()}"

b1 = Box(3, 4)
b2 = Box(5, 6)
print(b1.describe())
print(b2.describe())
